//! UDP mock **liquid-memory shard**: one AeonFlow frame per datagram, JSON payload.
//!
//! ```bash
//! GNOSIS_LIQUID_SHARD_PORT=19747 cargo run --manifest-path rtl-bridge/Cargo.toml --bin gnosis-liquid-shard-mock
//! ```
//!
//! Host sends `STREAM_LIQUID_SHARD_CMD` frames whose UTF-8 payload is JSON `{ "op": ... }`.
//! Shard replies with `STREAM_LIQUID_SHARD_RSP` and JSON body.

use std::net::UdpSocket;
use std::time::Duration;

use gnosis_rtl_bridge::aeon_flow_frame::{decode_frame, encode_frame, FlowFrame};
use gnosis_rtl_bridge::liquid_memory_shard::{
    handle_command_json, STREAM_LIQUID_SHARD_CMD, STREAM_LIQUID_SHARD_RSP,
};

fn main() {
    if let Err(e) = run() {
        eprintln!("gnosis-liquid-shard-mock: {e}");
        std::process::exit(1);
    }
}

fn run() -> Result<(), String> {
    let port: u16 = std::env::var("GNOSIS_LIQUID_SHARD_PORT")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(19_747);
    let cap: usize = std::env::var("GNOSIS_LIQUID_SHARD_BYTES")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(1024 * 1024);

    let sock = UdpSocket::bind(format!("127.0.0.1:{port}")).map_err(|e| e.to_string())?;
    sock.set_read_timeout(Some(Duration::from_secs(300)))
        .map_err(|e| e.to_string())?;

    let mut store = vec![0u8; cap];

    eprintln!(
        "gnosis-liquid-shard-mock: listening on udp://127.0.0.1:{} ({} MiB pool)",
        port,
        cap / (1024 * 1024)
    );

    let mut buf = vec![0u8; 65535];
    loop {
        let (n, peer) = match sock.recv_from(&mut buf) {
            Ok(v) => v,
            Err(e) => {
                eprintln!("recv_from: {e}");
                continue;
            }
        };
        let slice = &buf[..n];
        let (frame, _) = match decode_frame(slice, 0) {
            Ok(f) => f,
            Err(e) => {
                eprintln!("decode_frame from {peer}: {e}");
                continue;
            }
        };
        if frame.stream_id != STREAM_LIQUID_SHARD_CMD {
            eprintln!("ignore stream_id={} from {}", frame.stream_id, peer);
            continue;
        }
        let body = match std::str::from_utf8(&frame.payload) {
            Ok(s) => s.to_string(),
            Err(_) => {
                eprintln!("non-utf8 payload from {peer}");
                continue;
            }
        };

        let reply_json = match handle_command_json(&mut store, &body) {
            Ok(s) => s,
            Err(e) => serde_json::json!({ "ok": false, "error": e }).to_string(),
        };

        let rsp = FlowFrame {
            stream_id: STREAM_LIQUID_SHARD_RSP,
            sequence: frame.sequence.wrapping_add(1),
            flags: 0,
            payload: reply_json.into_bytes(),
        };
        let out = match encode_frame(&rsp) {
            Ok(b) => b,
            Err(e) => {
                eprintln!("encode_frame: {e}");
                continue;
            }
        };
        if let Err(e) = sock.send_to(&out, peer) {
            eprintln!("send_to {peer}: {e}");
        }
    }
}
